package main

import (
	"encoding/json"
	"fmt"
	"io"
	"log"
	"maps"
	"os"
	"reflect"
	"slices"
	"strings"

	"graphics.gd/internal/gdjson"
	"graphics.gd/internal/tool/generate/gdfunc"
	"graphics.gd/internal/tool/generate/gdtype"
	"graphics.gd/variant/String"
	"runtime.link/api/xray"
)

func main() {
	if err := generate(); err != nil {
		log.Fatal(err)
	}
}

func generate() error {
	spec, err := LoadSpecification()
	if err != nil {
		return xray.New(err)
	}
	// Load trivial methods list (optional, generated by the trivial-methods tool).
	if f, err := os.Open("./trivial_methods.json"); err == nil {
		var raw map[string][]string
		if err := json.NewDecoder(f).Decode(&raw); err != nil {
			f.Close()
			return xray.New(err)
		}
		f.Close()
		trivial := make(map[string]map[string]bool, len(raw))
		for cls, methods := range raw {
			m := make(map[string]bool, len(methods))
			for _, name := range methods {
				m[name] = true
			}
			trivial[cls] = m
		}
		gdfunc.TrivialMethods = trivial
	}
	if err := os.MkdirAll("./classdb", 0755); err != nil {
		return xray.New(err)
	}
	var classDB = make(ClassDB)
	for _, enum := range spec.GlobalEnums {
		classDB[strings.Replace(enum.Name, ".", "", -1)] = gdjson.Class{
			IsEnum:  true,
			Name:    strings.Replace(enum.Name, ".", "", -1),
			Package: "internal",
		}
	}
	for _, class := range spec.BuiltinClasses {
		for _, enum := range class.Enums {
			classDB[class.Name+strings.Replace(enum.Name, ".", "", -1)] = gdjson.Class{
				IsEnum:  true,
				Name:    class.Name + strings.Replace(enum.Name, ".", "", -1),
				Package: "internal",
			}
		}
	}
	spec.Classes = append(spec.Classes, gdjson.Class{
		Name:        "Rendering",
		IsEphemeral: true,
	})
	spec.Classes = append(spec.Classes, gdjson.Class{
		Name:        "GUI",
		IsEphemeral: true,
	})
	var global_enums = make(map[string]gdjson.Enum)
	for _, enum := range spec.GlobalEnums {
		global_enums[enum.Name] = enum
	}
	for i, class := range spec.Classes {
		var pkg = "internal"
		if !gdtype.Name(class.Name).InCore() {
			pkg = "classdb"
		}
		if class.Name == "GodotInstance" {
			class.Name = "Startup"
		}
		class.Package = pkg
		spec.Classes[i] = class
		classDB[class.Name] = class
	}
	var singletons = make(map[string]bool)
	for _, class := range spec.Singletons {
		singletons[class.Name] = true
		mod := classDB[class.Name]
		mod.IsSingleton = true
		classDB[class.Name] = mod
	}
	gdtype.ClassDB = classDB
	for _, class := range spec.Classes {
		if gdtype.Name(class.Name).InCore() {
			continue
		}
		if err := classDB.generateObjectPackage(class, singletons[class.Name], global_enums); err != nil {
			return xray.New(err)
		}
	}
	return nil
}

func generateEnum(code io.Writer, classDB map[string]gdjson.Class, prefix string, enum gdjson.Enum, original string) {
	rename, _ := gdtype.EnumNameOf(prefix, enum.Name)
	if enum.Name == "Error" {
		return
	} else {
		if original != "" {
			fmt.Fprintf(code, "type %v int64//gd:%s\n\n", rename, original)
		} else {
			fmt.Fprintf(code, "type %v int64\n\n", rename)
		}
	}
	fmt.Fprintf(code, "const (\n")
	for _, value := range enum.Values {
		n := convertName(value.Name)
		if n == enum.Name {
			n += "Default"
		}
		if value.Description != "" {
			description := strings.Replace(value.Description, "*/", "", -1)
			description = strings.TrimSpace(description)
			description = gdjson.DocsToGoDoc(description, classDB, "", "")
			description = strings.ReplaceAll(description, "\n", "\n\t\t// ")
			fmt.Fprintln(code, "\t\t// "+description)
		}
		fmt.Fprintf(code, "\t%v %v = %v\n", n, rename, value.Value)
	}
	fmt.Fprintf(code, ")\n")
}

func (classDB ClassDB) generateObjectPackage(class gdjson.Class, singleton bool, global_enums map[string]gdjson.Enum) error {
	if err := os.MkdirAll("./classdb/"+class.Name, 0755); err != nil {
		return xray.New(err)
	}
	file, err := os.Create("./classdb/" + class.Name + "/class.go")
	if err != nil {
		return xray.New(err)
	}
	var hasVirtual bool
	for _, method := range class.Methods {
		if method.IsVirtual {
			hasVirtual = true
			break
		}
	}
	defer file.Close()
	fmt.Fprintln(file, `// Code generated by the generate package DO NOT EDIT`)
	fmt.Fprintln(file)
	if class.Description != "" {
		fmt.Fprintln(file, "/*")
		fmt.Fprint(file, gdjson.DocsToGoDoc(class.Description, classDB, class.Name, class.Name))
		fmt.Fprintln(file)
		fmt.Fprint(file, "\n*/")
	}
	fmt.Fprintf(file, "\npackage %s\n\n", class.Name)
	if !class.IsEphemeral {
		if singleton {
			fmt.Fprintln(file, `import "sync"`)
		}
		fmt.Fprintln(file, `import "reflect"`)
		fmt.Fprintln(file, `import "slices"`)
		fmt.Fprintln(file, `import "graphics.gd/internal/pointers"`)
		fmt.Fprintln(file, `import "graphics.gd/internal/callframe"`)
		fmt.Fprintln(file, `import "graphics.gd/internal/gdextension"`)
		fmt.Fprintln(file, `import "graphics.gd/internal/gdreference"`)
		fmt.Fprintln(file, `import "graphics.gd/internal/noescape"`)
		if gdfunc.TrivialMethods != nil && len(gdfunc.TrivialMethods[class.Name]) > 0 {
			fmt.Fprintln(file, `import "graphics.gd/internal/jumponly"`)
		}
		fmt.Fprintln(file, `import gd "graphics.gd/internal"`)
		fmt.Fprintln(file, `import "graphics.gd/internal/gdclass"`)
		fmt.Fprintln(file, `import "graphics.gd/internal/ie"`)
		fmt.Fprintln(file, `import "graphics.gd/variant"`)
		fmt.Fprintln(file, `import "graphics.gd/variant/Angle"`)
		fmt.Fprintln(file, `import "graphics.gd/variant/Euler"`)
		fmt.Fprintln(file, `import "graphics.gd/variant/Signal"`)
		if class.Inherits != "" {
			super := classDB[class.Inherits]
			for super.Name != "" && super.Name != "Object" && super.Name != "RefCounted" && !classDB[super.Name].IsSingleton {
				super = classDB[super.Inherits]
			}
		}
		for pkg := range gdtype.ImportsForClass(class) {
			fmt.Fprintf(file, "import %q\n", pkg)
		}
		fmt.Fprintln(file)
		fmt.Fprintln(file, "var _ Object.ID")
		fmt.Fprintln(file, "type _ gdclass.Node")
		fmt.Fprintln(file, "var _ gd.String")
		fmt.Fprintln(file, "var _ RefCounted.Instance")
		fmt.Fprintln(file, "var _ reflect.Type")
		fmt.Fprintln(file, "var _ callframe.Frame")
		fmt.Fprintln(file, "var _ = pointers.Cycle")
		fmt.Fprintln(file, "var _ = Array.Nil")
		fmt.Fprintln(file, "var _ variant.Any")
		fmt.Fprintln(file, "var _ Callable.Function")
		fmt.Fprintln(file, "var _ Dictionary.Any")
		fmt.Fprintln(file, "var _ RID.Any")
		fmt.Fprintln(file, "var _ noescape.Variant")
		if gdfunc.TrivialMethods != nil && len(gdfunc.TrivialMethods[class.Name]) > 0 {
			fmt.Fprintln(file, "var _ = jumponly.PtrcallFn")
		}
		fmt.Fprintln(file, "var _ String.Readable")
		fmt.Fprintln(file, "var _ Path.ToNode")
		fmt.Fprintln(file, "var _ Packed.Bytes")
		fmt.Fprintln(file, "var _ Error.Code")
		fmt.Fprintln(file, "var _ Float.X")
		fmt.Fprintln(file, "var _ Signal.Any")
		fmt.Fprintln(file, "var _ Angle.Radians")
		fmt.Fprintln(file, "var _ Euler.Radians")
		fmt.Fprintln(file, "var _ gdextension.Object")
		fmt.Fprintln(file, "var _ = slices.Delete[[]struct{}, struct{}]")
	}
	fmt.Fprintln(file)
	var local_enums = make(map[string]bool)
	if !class.IsEphemeral {
		if class.Name != "Resource" {
			fmt.Fprintf(file, "/*\n")
			fmt.Fprintf(file, "ID is a typed object ID (reference) to an instance of this class, use it to store references to objects with\n")
			fmt.Fprintf(file, "unknown lifetimes, as an ID will not panic on use if the underlying object has been destroyed.\n")
			fmt.Fprintf(file, "*/\n")
			fmt.Fprintf(file, "type ID Object.ID\n")
			fmt.Fprintf(file, "func (id ID) Instance() (Instance, bool) { return Object.As[Instance](Object.ID(id).Instance()) }\n")
		}
		fmt.Fprintf(file, "/*\n")
		fmt.Fprintf(file, "Extension can be embedded in a new struct to create a Go extension of this class.\n\n")
		fmt.Fprintf(file, "T must be a type that is embedding this [Extension] as the first field.\n")
		fmt.Fprintf(file, "It is unsafe and invalid to use this type directly, or embedded in any other way.\n")
		if hasVirtual {
			fmt.Fprintf(file, "See [Interface] for methods that can be overridden by T.\n")
		}
		fmt.Fprintf(file, "*/\n")
		fmt.Fprintf(file, "type Extension[T gdclass.Interface] struct { gdclass.Extension[T, Instance] }\n")

		fmt.Fprintf(file, "/*\n")
		fmt.Fprintf(file, "Singleton can be embedded in a new struct to create a Go singleton extension of the class.\n\n")
		fmt.Fprintf(file, "It will become available as a global inside scripts and any any other Go Extension types will\n")
		fmt.Fprintf(file, "have any *T typed fields filled in to point at this singleton once they have been instantiated.\n\n")
		fmt.Fprintf(file, "T must be a type that is embedding this [Singleton] as the first field.\n")
		fmt.Fprintf(file, "It is unsafe and invalid to use this type directly, or embedded in any other way.\n")
		if hasVirtual {
			fmt.Fprintf(file, "See [Interface] for methods that can be overridden by T.\n")
		}
		fmt.Fprintf(file, "*/\n")
		fmt.Fprintf(file, "type Singleton[T gdclass.Interface] = Extension[T]\n")

		fmt.Fprintf(file, "// Instance of the class with convieniently typed arguments and results.\n")
		fmt.Fprintf(file, "type Instance [1]gdclass.%s\n", class.Name)
		fmt.Fprintf(file, "var otype gdextension.ObjectType\n")
		fmt.Fprintf(file, "var sname gdextension.StringName\n")
		fmt.Fprintf(file, "var methods struct {\n")
		for _, method := range class.Methods {
			if method.IsVirtual {
				continue
			}
			fmt.Fprintf(file, "\t%[1]v gdextension.MethodForClass `hash:\"%d\"`\n", fixReserved(method.Name), method.Hash)
		}
		fmt.Fprintf(file, "}\n")
		fmt.Fprintf(file, "func init() {\n")
		if class.Name != "Startup" {
			fmt.Fprintf(file, "\tgd.Links = append(gd.Links, func() {\n")
			fmt.Fprintf(file, "\t\tsname = gdextension.Host.Strings.Intern.UTF8(%q)\n", class.Name)
			fmt.Fprintf(file, "\t\totype = gdextension.Host.Objects.Type(sname)\n")
			fmt.Fprintf(file, "\t\tgd.LinkMethods(sname, &methods, %v)\n", class.APIType == "editor")
			fmt.Fprintf(file, "\t\t})\n")
		}
		fmt.Fprintf(file, "\tgd.RegisterCleanup(func() {\n")
		fmt.Fprintf(file, "\t\tnoescape.Free(gdextension.TypeStringName, &sname)\n")
		fmt.Fprintf(file, "\t})\n")
		fmt.Fprintf(file, "}\n")

		if class.Name != "Resource" {
			fmt.Fprintf(file, "func (self Instance) ID() ID { return ID(Object.Instance(self.AsObject()).ID()) }\n")
		}
		if singleton {
			fmt.Fprintf(file, "var self [1]gdclass.%s\n", class.Name)
			fmt.Fprintf(file, "var once sync.Once\n")
			fmt.Fprintf(file, "func singleton() {\n")
			fmt.Fprintf(file, "\tself[0] = gdclass.New%[1]v(gdreference.RawObject(gdextension.Host.Objects.Global(sname)))\n", class.Name)
			fmt.Fprintf(file, "}\n")
		} else {
			var hasDefaults bool
			for _, method := range class.Methods {
				for _, argument := range method.Arguments {
					if argument.DefaultValue != nil && !singleton && !method.IsStatic {
						hasDefaults = true
					}
				}
			}
			for _, peer_method := range gdjson.RelocationsReverse[class.Name] {
				peer, method, _ := strings.Cut(peer_method, ".")
				peerClass := classDB[peer]
				peerMethod := gdjson.Method{}
				for _, m := range peerClass.Methods {
					if m.Name == method {
						peerMethod = m
						break
					}
				}
				for _, argument := range peerMethod.Arguments {
					if argument.DefaultValue != nil && !singleton && !peerMethod.IsStatic {
						hasDefaults = true
					}
				}
			}
			if hasDefaults {
				fmt.Fprintf(file, "// MoreArgs is a container for [Instance] functions with additional 'optional' arguments.\n")
				fmt.Fprintf(file, "type MoreArgs [1]gdclass.%s\n", class.Name)
				fmt.Fprintf(file, "type Expanded = MoreArgs\n")

				fmt.Fprintf(file, "// MoreArgs enables certain functions to be called with additional 'optional' arguments.\n")
				fmt.Fprintf(file, "func (self Instance) MoreArgs() MoreArgs { return MoreArgs(self) }\n")
			}
			fmt.Fprintf(file, "// Nil is a nil/null instance of the class. Equivalent to the zero value.\n")
			fmt.Fprintf(file, "var Nil Instance\n")
			fmt.Fprintf(file, "type Any interface {\n")
			fmt.Fprintf(file, "\tgd.IsClass\n")
			fmt.Fprintf(file, "\tAs%s() Instance\n", class.Name)
			fmt.Fprintf(file, "}\n")
			if hasVirtual {
				generateInterface(file, classDB, class, true)
			}
		}
		var getter_setters = make(map[string]bool)
		for _, property := range class.Properties {
			if property.Getter != "" {
				getter_setters[property.Getter] = true
			}
			if property.Setter != "" {
				getter_setters[property.Setter] = true
			}
		}
		for _, method := range class.Methods {
			if _, ok := gdjson.Relocations[class.Name+"."+method.Name]; ok {
				continue // skip for now
			}
			if getter_setters[method.Name] {
				continue
			}
			classDB.simpleCall(file, class, method, singleton, true)
			var hasDefault bool
			for _, arg := range method.Arguments {
				if arg.DefaultValue != nil && !((singleton || method.IsStatic) && arg.DefaultValue != nil && gdjson.IsTheDefaultValueZero(*arg.DefaultValue)) {
					hasDefault = true
				}
			}
			if hasDefault {
				classDB.simpleCall(file, class, method, singleton, false)
			}
		}
		for _, name := range slices.Sorted(maps.Keys(gdjson.RelocationsReverse[class.Name])) {
			peer_method := gdjson.RelocationsReverse[class.Name][name]
			peer, method, _ := strings.Cut(peer_method, ".")
			peerClass := classDB[peer]
			var peerMethod gdjson.Method
			for _, m := range peerClass.Methods {
				if m.Name == method {
					peerMethod = m
					break
				}
			}
			peerMethod.Name = name
			if peerMethod.ReturnType == class.Name || peerMethod.ReturnValue.Type == class.Name {
				peerMethod.IsStatic = true
			}
			peerMethod.Arguments = append([]gdjson.Argument{
				{
					Name: "peer",
					Type: peerClass.Name,
				},
			}, peerMethod.Arguments...)
			relocated_args := make([]gdjson.Argument, 0, len(peerMethod.Arguments))
			for i, arg := range peerMethod.Arguments {
				if arg.Name == "peer" {
					continue
				}
				if !peerMethod.IsStatic && arg.Type == class.Name {
					arg.Name = "self"
					peerMethod.Arguments = slices.Concat(peerMethod.Arguments[:i], peerMethod.Arguments[i+1:])
				}
				relocated_args = append(relocated_args, arg)
			}
			peerMethod.ArgumentsRemapped = relocated_args
			classDB.simpleRelocatedCall(file, class, peerMethod, peerClass, method, true)
			var hasDefault bool
			for _, argument := range peerMethod.Arguments {
				if argument.DefaultValue != nil {
					hasDefault = true
				}
			}
			if hasDefault {
				classDB.simpleRelocatedCall(file, class, peerMethod, peerClass, method, false)
			}
		}
		fmt.Fprintf(file, `// Advanced exposes a 1:1 low-level instance of the class, undocumented, for those who know what they are doing.`)
		if singleton {
			fmt.Fprintf(file, "\nfunc Advanced() class { once.Do(singleton); return self }\n")
		} else {
			fmt.Fprintf(file, "\ntype Advanced = class\n")
		}
		fmt.Fprintf(file, "type class [1]gdclass.%s\n", class.Name)
		fmt.Fprintf(file, "func (o class) AsObject() [1]gdreference.Object { return *(*[1]gdreference.Object)(ie.As(&o)) }\n")
		fmt.Fprintln(file, "func (self *class) SetObject(obj [1]gdreference.Object) bool {")
		fmt.Fprintln(file, "\tif gdextension.Host.Objects.Cast(gdreference.GetObject(obj[0]), otype) != 0 {")
		fmt.Fprintf(file, "\t\tself[0] = gdclass.New%[1]s(obj[0])\n", class.Name)
		fmt.Fprintln(file, "\t\treturn true")
		fmt.Fprintln(file, "\t}")
		fmt.Fprintln(file, "\treturn false")
		fmt.Fprintln(file, "}")
		fmt.Fprintln(file, "func (self *Instance) SetObject(obj [1]gdreference.Object) bool {")
		fmt.Fprintln(file, "\tif gdextension.Host.Objects.Cast(gdreference.GetObject(obj[0]), otype) != 0 {")
		fmt.Fprintf(file, "\t\tself[0] = gdclass.New%[1]s(obj[0])\n", class.Name)
		fmt.Fprintln(file, "\t\treturn true")
		fmt.Fprintln(file, "\t}")
		fmt.Fprintln(file, "\treturn false")
		fmt.Fprintln(file, "}")

		fmt.Fprintf(file, "func (o Instance) AsObject() [1]gdreference.Object { return *(*[1]gdreference.Object)(ie.As(&o)) }\n")
		fmt.Fprintln(file, "func (o *Extension[T]) AsObject() [1]gdreference.Object { return o.Super().AsObject() }")
		if !singleton {
			classDB.new(file, class)
		}
		classDB.properties(file, class, singleton)
		for _, method := range class.Methods {
			gdfunc.Generate(file, classDB, class.Package, class, method, gdfunc.TypeDefault, getter_setters[method.Name], singleton)
		}
		for _, signal := range class.Signals {
			classDB.signalCall(file, class, signal, singleton)
		}
		super := classDB[class.Inherits]
		if class.Inherits != "" {
			var i = 1
			if !singleton {
				fmt.Fprintf(file, "\nfunc (o class) As%[1]v() Advanced { return Advanced(o) }\n", class.Name)
				fmt.Fprintf(file, "func (o Instance) As%[1]v() Instance { return o }\n", class.Name)
				fmt.Fprintf(file, "func (o *Extension[T]) As%[1]v() Instance { return o.Super() }\n", class.Name)
			}
			super := classDB[class.Inherits]
			for super.Name != "" && super.Name != "Object" {
				if classDB[super.Name].IsSingleton {
					super = classDB[super.Inherits]
					continue
				}
				if super.Name == "RefCounted" {
					fmt.Fprintf(file, "func (o class) AsRefCounted() ie.RC { return *(*ie.RC)(ie.As(&o)) }\n")
					fmt.Fprintf(file, "func (o *Extension[T]) AsRefCounted() ie.RC { return o.Super().AsRefCounted() }\n")
					if !singleton {
						fmt.Fprintf(file, "func (o Instance) AsRefCounted() ie.RC { return *(*ie.RC)(ie.As(&o)) }\n")
					}
				} else {
					fmt.Fprintf(file, "func (o class) As%[2]v() %[2]v.Advanced { return *(*%[2]v.Advanced)(ie.As(&o)) }\n", class.Name, super.Name)
					fmt.Fprintf(file, "func (o *Extension[T]) As%[2]v() %[2]v.Instance { return o.Super().As%[2]v() }\n", class.Name, super.Name)
					if !singleton {
						fmt.Fprintf(file, "func (o Instance) As%[2]v() %[2]v.Instance { return *(*%[2]v.Instance)(ie.As(&o)) }\n", class.Name, super.Name)
					}
				}
				i++
				super = classDB[super.Inherits]
			}
		}
		for _, self := range []string{"class", "Instance"} {
			fmt.Fprintf(file, "\nfunc (self %s) Virtual(name string) reflect.Value {\n", self)
			fmt.Fprintf(file, "\tswitch name {\n")
			for _, method := range class.Methods {
				if method.IsVirtual {
					fmt.Fprintf(file, "\tcase \"%v\": return reflect.ValueOf(self.%v);\n", method.Name, method.Name)
				}
			}
			if class.Inherits != "" && !classDB[class.Inherits].IsSingleton {
				var name = "Instance"
				if self != "Instance" {
					name = "Advanced"
				}
				fmt.Fprintf(file, "\tdefault: return gd.VirtualByName(%s.%s(self.As%[1]s()), name)\n", super.Name, name)
			} else {
				fmt.Fprintf(file, "\tdefault: return reflect.Value{}\n")
			}
			fmt.Fprintf(file, "\t}\n")
			fmt.Fprintf(file, "}\n")
		}
		fmt.Fprintf(file, `func init() {`)
		fmt.Fprintf(file, `gdclass.Register("%s", func(ptr gdreference.Object) any { return Instance{gdclass.New%[1]s(ptr)} })`, class.Name)
		fmt.Fprintf(file, "}\n")
		if class.Name != "RenderingDevice" {
			for _, enum := range class.Enums {
				if _, ok := gdjson.Renumeration[class.Name+"."+enum.Name]; !ok {
					generateEnum(file, classDB, class.Name, enum, class.Name+"."+enum.Name)
				}
			}
		}
	}
	if class.Name == "Rendering" {
		for _, enum := range classDB["RenderingDevice"].Enums {
			if enum.Name == "RenderingDevice" {
				continue
			}
			if _, ok := gdjson.Renumeration[class.Name+"."+enum.Name]; !ok {
				generateEnum(file, classDB, class.Name, enum, "RenderingDevice."+enum.Name)
			}
		}
	}
	for _, key := range slices.Sorted(maps.Keys(gdjson.Renumeration)) {
		renum := gdjson.Renumeration[key]
		old_host, old_name, notGlobal := strings.Cut(key, ".")
		host, new_name, _ := strings.Cut(renum, ".")
		if host == class.Name {
			enums := classDB[old_host].Enums
			if !notGlobal {
				enums = slices.Collect(maps.Values(global_enums))
				old_name = key
			}
			for _, enum := range enums {
				if enum.Name == old_name {
					enum.Name = new_name
					generateEnum(file, classDB, class.Name, enum, key)
					break
				}
			}
		}
	}
	for _, key := range slices.Sorted(maps.Keys(local_enums)) {
		enum := global_enums[key]
		generateEnum(file, classDB, "", enum, "")
	}
	generateStructables(file)
	var constTypes = make(map[string]bool)
	for _, prefix := range slices.Sorted(maps.Keys(gdjson.Consitution[class.Name])) {
		retype := gdjson.Consitution[class.Name][prefix]
		if strings.Contains(retype, ".") || retype == "" || retype == "-" || retype == "int" || constTypes[retype] {
			continue
		}
		constTypes[retype] = true
		fmt.Fprintf(file, "type %s int\n", retype)
	}
	for _, constant := range class.Constants {
		for _, prefix := range slices.Sorted(maps.Keys(gdjson.Consitution[class.Name])) {
			retype := gdjson.Consitution[class.Name][prefix]
			if strings.HasPrefix(constant.Name, prefix) {
				if retype != "-" {
					fmt.Fprintf(file, "const %s %s = %v //gd:%s.%s\n",
						String.ToPascalCase(constant.Name), retype, constant.Value, class.Name, constant.Name)
					break
				}
			}
		}
	}
	return nil
}

func registerStructables(rtype reflect.Type) {
	if rtype.PkgPath() == "graphics.gd/internal/gdjson" {
		StructablesInThisPackageGlobalHack[rtype] = true
	}
	switch rtype.Kind() {
	case reflect.Array, reflect.Slice:
		registerStructables(rtype.Elem())
	case reflect.Map:
		registerStructables(rtype.Key())
		registerStructables(rtype.Elem())
	case reflect.Struct:
		for field := range rtype.Fields() {
			registerStructables(field.Type)
		}
	}
}

func generateStructables(file io.Writer) {
	var sortable = make([]string, 0, len(StructablesInThisPackageGlobalHack))
	for rtype := range StructablesInThisPackageGlobalHack {
		switch rtype.Kind() {
		case reflect.Map:
			name := rtype.Name()
			name = strings.ReplaceAll(name, "interface{}", "any")
			name = strings.ReplaceAll(name, "interface {}", "any")
			sortable = append(sortable,
				fmt.Sprintf("type %v map[%v]%v\n", name,
					strings.ReplaceAll(rtype.Key().String(), "interface {}", "any"),
					strings.ReplaceAll(rtype.Elem().String(), "interface {}", "any")))
		case reflect.Struct:
			var w strings.Builder
			fmt.Fprintf(&w, "type %v struct {\n", rtype.Name())
			for field := range rtype.Fields() {
				if field.PkgPath != "" {
					continue
				}
				ftype := field.Type.String()
				if override, ok := field.Tag.Lookup("type"); ok {
					ftype = override
				}
				ftype = strings.ReplaceAll(ftype, "gdjson.", "")
				ftype = strings.ReplaceAll(ftype, "interface{}", "any")
				ftype = strings.ReplaceAll(ftype, "interface {}", "any")
				gdTag := field.Tag.Get("gd")
				fmt.Fprintf(&w, "%v %v `gd:\"%s\"`\n", field.Name, ftype, gdTag)
			}
			fmt.Fprintf(&w, "}\n")
			sortable = append(sortable, w.String())
		}
	}
	slices.Sort(sortable)
	for _, s := range sortable {
		fmt.Fprint(file, s)
	}
	clear(StructablesInThisPackageGlobalHack)
}

// isSliceableCount returns true if the argument named argName is the count
// companion of any Sliceable entry for the given class and method.
func isSliceableCount(className, methodName string, args []gdjson.Argument, argName string) bool {
	for _, other := range args {
		key := className + "." + methodName + "." + other.Name
		if s, ok := gdjson.Sliceables[key]; ok && s.Count == argName {
			return true
		}
	}
	return false
}

func generateInterface(file io.Writer, classDB ClassDB, class gdjson.Class, impl bool) {
	fmt.Fprintf(file, "\ntype Interface interface {\n")
	for _, method := range class.Methods {
		if method.IsVirtual {
			if method.Description != "" {
				description := strings.ReplaceAll(method.Description, "*/", "")
				description = strings.TrimSpace(description)
				description = gdjson.DocsToGoDoc(description, classDB, class.Name, "")
				description = strings.ReplaceAll(description, "\n", "\n\t\t// ")
				fmt.Fprintln(file, "\t\t// "+description)
			}
			fmt.Fprintf(file, "\t%s(", convertName(method.Name))
			first := true
			for _, arg := range method.Arguments {
				if isSliceableCount(class.Name, method.Name, method.Arguments, arg.Name) {
					continue
				}
				if !first {
					fmt.Fprint(file, ", ")
				}
				first = false
				fmt.Fprint(file, fixReserved(arg.Name), " ", classDB.convertTypeSimple(class, class.Name+"."+method.Name+"."+arg.Name, arg.Meta, arg.Type))
			}
			fmt.Fprint(file, ") ", classDB.convertTypeSimple(class, class.Name+"."+method.Name+".", method.ReturnValue.Meta, method.ReturnValue.Type))
			fmt.Fprintln(file)
		}
	}
	fmt.Fprintf(file, "}\n")

	if !impl {
		return
	}

	fmt.Fprintf(file, "// Implementation implements [Interface] with empty methods.\n")
	fmt.Fprintf(file, "type Implementation = implementation\n\n")
	fmt.Fprintf(file, "type implementation struct{}\n")

	for _, method := range class.Methods {
		if method.IsVirtual {
			fmt.Fprintf(file, "func (self implementation) %[1]v(", convertName(method.Name))
			first := true
			for _, arg := range method.Arguments {
				if isSliceableCount(class.Name, method.Name, method.Arguments, arg.Name) {
					continue
				}
				if !first {
					fmt.Fprint(file, ", ")
				}
				first = false
				fmt.Fprint(file, fixReserved(arg.Name), " ", classDB.convertTypeSimple(class, class.Name+"."+method.Name+"."+arg.Name, arg.Meta, arg.Type))
			}
			fmt.Fprint(file, ")")
			if method.ReturnValue.Type != "" {
				fmt.Fprintf(file, "(_ %s)", classDB.convertTypeSimple(class, class.Name+"."+method.Name+".", method.ReturnValue.Meta, method.ReturnValue.Type))
			}
			fmt.Fprintln(file, " { ")
			if method.ReturnValue.Type != "" {
				fmt.Fprintln(file, "\treturn")
			}
			fmt.Fprintln(file, " }")
		}
	}
}
